import { useEffect, useRef, useState } from 'react';

export function CookieConsentBannerWithAdaptiveLayou() {
  const rootRef = useRef<HTMLDivElement>(null);
  const [compact, setCompact] = useState(false);

  useEffect(() => {
    const node = rootRef.current;
    if (!node) return;
    const observer = new ResizeObserver(([entry]) => setCompact(entry.contentRect.width < 560));
    observer.observe(node);
    return () => observer.disconnect();
  }, []);

  return (
    <section ref={rootRef} data-compact={compact} className="grid gap-3 data-[compact=true]:grid-cols-1 data-[compact=false]:grid-cols-[16rem_1fr]">
      <nav aria-label="Section navigation" className="overflow-x-auto whitespace-nowrap">{/* actions remain reachable on touch and keyboard */}</nav>
      <main className="min-w-0">{/* Cookie consent banner with adaptive layout per container width */}</main>
    </section>
  );
}

