// State: Set<string> of IDs. Filter doesn't clear, but rows not visible don't render checkboxes.
// 'Selected: 5 (3 filtered, 2 hidden)' message for clarity.
import { useState } from 'react';

export function FilterableSelectable({ rows, filter }: { rows: any[]; filter: string }) {
  const [selected, setSelected] = useState<Set<string>>(new Set());
  const filtered = rows.filter((r) => r.name.includes(filter));
  const visibleSelected = filtered.filter((r) => selected.has(r.id)).length;
  const hiddenSelected = selected.size - visibleSelected;

  return (
    <div>
      {selected.size > 0 && <p className="text-sm">Selected: {selected.size} ({visibleSelected} visible{hiddenSelected > 0 ? `, ${hiddenSelected} hidden by filter` : ''})</p>}
      {/* table */}
    </div>
  );
}

